    var w3 = canvas.width;
    var h2 = canvas.height;
    ctx.setTransform(1, 0, 0, 1, 0, 0);
    ctx.clearRect(0, 0, w3, h2);
    var zmin = this._z[0];
    var zmax = this._z[1];
    var t2 = this.tab_;
    var d3 = t2[t2.length - 1][0];
    var ti = t2[t2.length - 1][2];
    var i2;
    if (!d3) {
      console.error("[ol/control/Profile] no data...", t2);
      return;
    }
    ctx.setTransform(1, 0, 0, 1, this.margin_.left, h2 - this.margin_.bottom);
    var ratio = this.ratio;
    w3 -= this.margin_.right + this.margin_.left;
    h2 -= this.margin_.top + this.margin_.bottom;
    var textFillColor = this._style.getText().getFill().getColor();
    ctx.strokeStyle = textFillColor ? asString(textFillColor) : "#000";
    ctx.lineWidth = 0.5 * ratio;
